<script setup lang="ts">import{onMounted,ref}from'vue';import{callApi}from'../api';import{useAuthStore}from'../stores/auth';const cards=[['合作方案','版本与生效日期'],['结算单','冻结基数及规则快照'],['保证金','缴纳、退回与资金占用'],['项目结项','普通或带遗留事项结项']];interface Option{id:string;projectName?:string;name?:string};const auth=useAuthStore(),projects=ref<Option[]>([]),partners=ref<Option[]>([]),summary=ref({planCount:0,settledAmount:'0.00',occupiedDeposit:'0.00',pendingCloseCount:0}),error=ref<string|null>(null),showForm=ref(false),saving=ref(false);const form=ref({projectId:'',partnerId:'',settlementMethod:'RATIO',fixedAmount:null as number|null,ratio:.2 as number|null,calculationBasis:'ACTUAL_RECEIPTS',upperLimit:null as number|null,lowerLimit:null as number|null,effectiveFrom:new Date().toISOString().slice(0,10),effectiveTo:null as string|null,conditions:''});async function load(){try{const[s,p,c]=await Promise.all([callApi<typeof summary.value>('settlement.summary',{}),callApi<{items:Option[]}>('project.list',{page:1,pageSize:50}),callApi<{items:Option[]}>('crm.counterparty.list',{page:1,pageSize:50})]);summary.value=s;projects.value=p.items;partners.value=c.items}catch(e){error.value=e instanceof Error?e.message:'加载失败'}};onMounted(load);async function createPlan(){if(!auth.user)return;saving.value=true;error.value=null;try{await callApi('partner.plan.create',{...form.value,fixedAmount:form.value.settlementMethod==='FIXED'?form.value.fixedAmount:null,ratio:form.value.settlementMethod==='RATIO'?form.value.ratio:null,ownerId:auth.user.employeeId,deductibleCostScope:[],effectiveTo:form.value.effectiveTo||null,conditions:form.value.conditions||null});showForm.value=false;await load()}catch(e){error.value=e instanceof Error?e.message:'保存失败'}finally{saving.value=false}}</script>
<template><main class="page"><header class="page-header"><div><p class="eyebrow">SETTLEMENT & CLOSE</p><h1>结算、保证金与结项</h1></div><button class="primary-action" @click="showForm=!showForm">{{showForm?'取消':'新增合作方案'}}</button></header><p v-if="error" class="error">{{error}}</p><section class="contract-panels"><article><p>合作方案</p><strong>{{summary.planCount}}</strong><small>全部有效版本</small></article><article><p>已审批结算</p><strong>¥ {{summary.settledAmount}}</strong><small>已确认成本</small></article><article><p>保证金占用</p><strong>¥ {{summary.occupiedDeposit}}</strong><small>已缴未退</small></article></section><form v-if="showForm" class="entity-form" @submit.prevent="createPlan"><label>项目<select v-model="form.projectId" required><option value="" disabled>请选择</option><option v-for="p in projects" :key="p.id" :value="p.id">{{p.projectName}}</option></select></label><label>合作方<select v-model="form.partnerId" required><option value="" disabled>请选择</option><option v-for="p in partners" :key="p.id" :value="p.id">{{p.name}}</option></select></label><label>结算方式<select v-model="form.settlementMethod"><option value="RATIO">比例</option><option value="FIXED">固定金额</option></select></label><label v-if="form.settlementMethod==='RATIO'">比例<input v-model.number="form.ratio" type="number" min="0" max="1" step="0.000001" required></label><label v-else>固定金额<input v-model.number="form.fixedAmount" type="number" min="0" step="0.01" required></label><label>计算基数<select v-model="form.calculationBasis"><option value="ACTUAL_RECEIPTS">实际收款</option><option value="CONTRACT_REVENUE_EX_TAX">合同不含税收入</option><option value="PROJECT_GROSS_PROFIT">项目毛利</option><option value="FIXED">固定金额</option></select></label><label>生效日期<input v-model="form.effectiveFrom" type="date" required></label><label>上限<input v-model.number="form.upperLimit" type="number" min="0" step="0.01"></label><label>下限<input v-model.number="form.lowerLimit" type="number" min="0" step="0.01"></label><label class="wide">条件<textarea v-model="form.conditions"></textarea></label><button :disabled="saving">{{saving?'保存中…':'保存方案'}}</button></form><section class="module-grid"><article v-for="([title,detail],i) in cards" :key="title" class="module-card"><span class="module-icon">{{i+1}}</span><h2>{{title}}</h2><p>{{detail}}</p></article></section></main></template>
